mapper.select:
select id, field_id, locale, display_title, placeholder, help_text, status,
       create_by, create_time, update_by, update_time, note
from sys_module_field_title
where field_id = #{fieldId}
  and locale = #{locale}
limit 1

mapper.insert:
insert into sys_module_field_title (
    id, field_id, locale, display_title, placeholder, help_text, status,
    create_by, create_time, update_by, update_time, note
) values (
    #{id}, #{fieldId}, #{locale}, #{displayTitle}, #{placeholder}, #{helpText}, #{status},
    #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{note}
)
